import{_ as i,o as e,c as l,az as s}from"./chunks/framework.CHcpZsfo.js";const o="/docs/img/2026/04/21/1776738282589.png",t="/docs/img/2026/04/21/1776738420311.png",r="/docs/img/2026/04/21/1776738465094.png",n="/docs/img/2026/04/21/1776738580110.png",h="/docs/img/2026/04/21/1776738601831.png",d="/docs/img/2026/04/21/1776738612324.png",c="/docs/img/2026/04/21/1776738768997.png",g="/docs/img/2026/04/21/1776738784625.png",p="/docs/img/2026/04/21/1776738817921.png",m="/docs/img/2026/04/21/1776738828065.png",x=JSON.parse('{"title":"真机调试网页","description":"Android 与 iOS 真机调试网页方案整理","frontmatter":{"title":"真机调试网页","description":"Android 与 iOS 真机调试网页方案整理","isOriginal":false,"author":"小T的草屋","articleLink":"https://works996.icu/inspect-on-real-device/","date":"2026/04/21 18:22","isTop":false,"categories":["工具四海谈"],"tags":["Chrome","Safari","Android","iOS","调试"]},"headers":[],"relativePath":"categories/tools/2026/04/21/真机调试网页.md","filePath":"categories/tools/2026/04/21/真机调试网页.md","lastUpdated":1776739090000}'),b={name:"categories/tools/2026/04/21/真机调试网页.md"};function u(k,a,f,_,C,q){return e(),l("div",null,[...a[0]||(a[0]=[s('<h1 id="真机调试网页" tabindex="-1">真机调试网页 <a class="header-anchor" href="#真机调试网页" aria-label="Permalink to &quot;真机调试网页&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><blockquote><p>在PC端使用H5技术开发和调试时，由于主流浏览器Chrome、Safari、Firefox的devtools已经做的比较成熟，提供了较好的开发体验。但在移动端开发时，无法直接使用devtools。虽说H5技术具有跨平台性，理论上可以在PC上开发，直接运行于移动端，但事实是移动端webview内核的实现并非与PC端一模一样，有很多兼容性的问题只能在移动端重现，因此有一些场景不可避免的需要在移动端真机上进行开发和调试。那有没有办法让移动端H5开发和PC上有一样的体验呢？答案就是——Remote Debugging(远程调试)</p></blockquote><h2 id="remote-debugging" tabindex="-1">Remote Debugging <a class="header-anchor" href="#remote-debugging" aria-label="Permalink to &quot;Remote Debugging&quot;">​</a></h2><h3 id="原理" tabindex="-1">原理 <a class="header-anchor" href="#原理" aria-label="Permalink to &quot;原理&quot;">​</a></h3><ul><li><p>本文重点介绍如何使用，关于devtools的工作原理，后面有时间会专门介绍。</p></li><li><p><img src="'+o+'" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"></p></li><li><p>Android 页面调试，优先使用 Chrome 自带的远程调试能力。</p></li><li><p>iPhone 上的 Safari 页面调试，优先使用 Safari 的开发菜单。</p></li><li><p>如果希望继续用 Chrome 调试 iPhone 页面，可以通过代理工具把 iOS 的 WebKit 调试能力桥接到 Chrome DevTools。</p></li></ul><h2 id="android-真机调试" tabindex="-1">Android 真机调试 <a class="header-anchor" href="#android-真机调试" aria-label="Permalink to &quot;Android 真机调试&quot;">​</a></h2><h3 id="一、打开手机usb调试功能" tabindex="-1">一、打开手机USB调试功能 <a class="header-anchor" href="#一、打开手机usb调试功能" aria-label="Permalink to &quot;一、打开手机USB调试功能&quot;">​</a></h3><ol><li>设置 -&gt; 关于手机 -&gt; 系统版本。</li><li>连续点击系统版本，一般5次以内就会弹出“已进入开发者模式”的toast。</li><li>设置 -&gt; 系统 -&gt; 开发人员选项 -&gt; 打开USB调试</li><li><img src="'+t+'" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"></li></ol><h3 id="二、usb连接手机与电脑" tabindex="-1">二、USB连接手机与电脑 <a class="header-anchor" href="#二、usb连接手机与电脑" aria-label="Permalink to &quot;二、USB连接手机与电脑&quot;">​</a></h3><ol><li>用数据线连接手机与电脑</li><li>手机上弹出如下对话框，一定要选确定/允许。</li><li><img src="'+r+'" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"></li><li>电脑上也会弹出授权对话框，同样要选允许。</li></ol><h3 id="三、开始调试" tabindex="-1">三、开始调试 <a class="header-anchor" href="#三、开始调试" aria-label="Permalink to &quot;三、开始调试&quot;">​</a></h3><ol><li><p>手机chrome浏览器打开待调试页面。</p></li><li><p>在PC chrome浏览器地址栏输入 <b>chrome://inspect/#devices</b> -&gt; 找到待调试页面 -&gt; 点击 <b>inspect</b> 打开devtools。 <img src="'+n+'" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"><br><img src="'+h+'" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"></p></li><li><p>用chrome devtools调试 <img src="'+d+'" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"></p></li></ol><h2 id="ios-safari-真机调试" tabindex="-1">iOS Safari 真机调试 <a class="header-anchor" href="#ios-safari-真机调试" aria-label="Permalink to &quot;iOS Safari 真机调试&quot;">​</a></h2><h3 id="一、开启调试工具" tabindex="-1">一、开启调试工具 <a class="header-anchor" href="#一、开启调试工具" aria-label="Permalink to &quot;一、开启调试工具&quot;">​</a></h3><ol><li>手机端: 设置 -&gt; Safari -&gt; 高级 -&gt; Web Inspector</li><li><img src="'+c+'" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"></li><li>PC端: 打开Safari -&gt; 菜单 -&gt; Safari浏览器 -&gt; 设置 -&gt; 高级 -&gt; 显示网页开发者功能</li><li><img src="'+g+'" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"></li></ol><h3 id="二、usb连接手机与电脑-1" tabindex="-1">二、USB连接手机与电脑 <a class="header-anchor" href="#二、usb连接手机与电脑-1" aria-label="Permalink to &quot;二、USB连接手机与电脑&quot;">​</a></h3><h3 id="三、开始调试-1" tabindex="-1">三、开始调试 <a class="header-anchor" href="#三、开始调试-1" aria-label="Permalink to &quot;三、开始调试&quot;">​</a></h3><ol><li>手机Safari浏览器打开待调试页面。</li><li>打开PC safari浏览器 -&gt; 开发 -&gt; 选取对应手机 -&gt; 点击待调试页面。</li><li><img src="'+p+'" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"></li><li>用safari devtools调试</li><li><img src="'+m+`" alt="image-2026-04-21" lang="zh-CN" data-fancybox="gallery"></li></ol><h2 id="用chrome-devtools调试手机safari网页" tabindex="-1">用chrome devtools调试手机safari网页 <a class="header-anchor" href="#用chrome-devtools调试手机safari网页" aria-label="Permalink to &quot;用chrome devtools调试手机safari网页&quot;">​</a></h2><p>原文给出的思路是先启动 WebKit 调试代理，再把调试端口接入 Chrome。</p><h3 id="安装工具" tabindex="-1">安装工具 <a class="header-anchor" href="#安装工具" aria-label="Permalink to &quot;安装工具&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark-dimmed vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#F69D50;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#96D0FF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#96D0FF;"> ios-webkit-debug-proxy</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#F69D50;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#96D0FF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#6CB6FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#96D0FF;"> remotedebug-ios-webkit-adapter</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="启动代理" tabindex="-1">启动代理 <a class="header-anchor" href="#启动代理" aria-label="Permalink to &quot;启动代理&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark-dimmed vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#F69D50;">ios_webkit_debug_proxy</span><span style="--shiki-light:#005CC5;--shiki-dark:#6CB6FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#96D0FF;"> chrome-devtools://devtools/bundled/inspector.html</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#F69D50;">remotedebug_ios_webkit_adapter</span><span style="--shiki-light:#005CC5;--shiki-dark:#6CB6FF;"> --port=9000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="chrome-连接方式" tabindex="-1">Chrome 连接方式 <a class="header-anchor" href="#chrome-连接方式" aria-label="Permalink to &quot;Chrome 连接方式&quot;">​</a></h3><ol><li>iPhone 连接电脑后，先在 Safari 中打开目标页面。</li><li>电脑端打开 <code>chrome://inspect</code>。</li><li>在 <code>Configure</code> 中添加 <code>localhost:9000</code>。</li><li>等待页面出现在列表中后，点击 <code>inspect</code> 即可。</li></ol><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>平时主要使用 Chrome DevTools，希望 iOS 也保持同一套调试习惯。</li><li>需要同时调试 Android 和 iPhone 页面，想统一入口。</li><li>想借助 Chrome 的元素面板、网络面板和控制台完成排查。</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><ul><li>Android：Chrome 远程调试最直接。</li><li>iOS Safari：Safari 开发菜单最稳定。</li><li>iPhone + Chrome：通过代理桥接后也能调试。</li><li>真机调试前，先检查设备授权、调试开关和页面是否已打开，通常能省掉大部分排查时间。</li></ul>`,31)])])}const P=i(b,[["render",u]]);export{x as __pageData,P as default};
